import { useState, useEffect } from 'react';
import React from 'react';
import './Chatting.css';
import { ChatContainer, MessageList, Message, MessageInput } from '@chatscope/chat-ui-kit-react';
import '@chatscope/chat-ui-kit-styles/dist/default/styles.min.css';
import Modal from './modal';

const Chatting = () => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [messages, setMessages] = useState([]); // 현재 채팅 메시지 목록
  const [newMessage, setNewMessage] = useState(''); // 사용자가 입력한 메시지

  useEffect(() => {
    fetchMessages(); // 컴포넌트가 처음 렌더링될 때 기존 채팅 기록 불러오기
  }, []);

  // 🔹 기존 메시지를 불러오는 함수
  const fetchMessages = async () => {
    try {
      const response = await fetch('http://127.0.0.1:4000/get-messages'); // 백엔드에서 저장된 메시지 불러옴
      const data = await response.json();
      setMessages(data);
    } catch (error) {
      console.error('메시지 불러오기 오류:', error);
    }
  };

  // 🔹 메시지 전송 함수 (DB 저장)
  const sendMessage = async () => {
    if (!newMessage.trim()) return; // 빈 메시지는 전송하지 않음

    const messageData = {
      message: newMessage,
      sender: '사용자' // 실제 로그인 기능 추가 시 유저 정보 사용 가능
    };

    try {
      const response = await fetch('http://127.0.0.1:4000/save-message', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(messageData),
      });

      if (response.ok) {
        setMessages([...messages, messageData]); // 새 메시지를 화면에 추가
        setNewMessage(''); // 입력 필드 초기화
      }
    } catch (error) {
      console.error('메시지 저장 오류:', error);
    }
  };

  return (
    <div className='chatting'>
      <ul>
        <li className='name'>사용자가 지정한 애칭</li>
        <li className='chatting_body' style={{ width: 786 }}>
          <ChatContainer>
            <MessageList style={{ marginTop: 15 }}>
              {messages.map((msg, index) => (
                <Message
                  key={index}
                  model={{
                    message: msg.message,
                    direction: 'incoming',
                    position: 'first'
                  }}
                />
              ))}
            </MessageList>
            {/* 🔹 MessageInput에서 엔터 또는 버튼 클릭 시 sendMessage 실행 */}
            <MessageInput
              placeholder="메시지 작성"
              value={newMessage}
              onChange={(val) => setNewMessage(val)}
              onSend={sendMessage} // 엔터 키 또는 버튼 클릭 시 실행
            />
          </ChatContainer>
        </li>
        {isModalOpen && <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} />}
      </ul>
    </div>
  );
};

export default Chatting;
